pub struct CalibrationInput {
    /// sRGB pixels f32 [0,1] in row-major order, length = width * height * 3 (as u8 RGB)
    pub pixels: Vec<u8>,
    /// RAUNE-Net enhanced target, same size, RGB u8
    pub target: Vec<u8>,
    /// Depth map f32 [0,1], length = width * height
    pub depth: Vec<f32>,
    pub width: usize,
    pub height: usize,
}
